class Solution {
    public int findMinimumOperations(String s1, String s2, String s3) {
        int n = Math.min(s1.length(), Math.min(s2.length(), s3.length()));
        for (int i = 0; i <= n; i++) {
            if (s1.length() - i == s2.length() - i && s2.length() - i == s3.length() - i 
                && s1.substring(i).equals(s2.substring(i)) && s2.substring(i).equals(s3.substring(i))) {
                return i;
            }
        }
        return -1;
    }
}
